  const zoneComparisonData = {
    labels: ["Central", "North", "South", "East", "West"],

    datasets: [
      {
        label: "Avg Congestion",
        data: [85, 72, 68, 78, 65],
        backgroundColor: "rgba(239,68,68,0.7)",
      },

      {
        label: "Peak Congestion",
        data: [95, 88, 82, 92, 78],
        backgroundColor: "rgba(251,146,60,0.7)",
      },
    ],
  };

  const performanceMetrics = {
    labels: [
      "Signal Efficiency",
      "Response Time",
      "Throughput",
      "Queue Length",
      "Wait Time Reduction",
    ],

    datasets: [
