        label: "Current Performance",

        data: [85, 78, 82, 70, 88],

        backgroundColor: "rgba(34,197,94,0.2)",
        borderColor: "rgb(34,197,94)",
        pointBackgroundColor: "rgb(34,197,94)",
      },

      {
        label: "Target Performance",

        data: [90, 85, 90, 80, 95],

        backgroundColor: "rgba(59,130,246,0.2)",
